397	  -- convert string to real
398	  function from_str(input : string) return real is
399	    constant Nbsp_c       : character := character'val(160);
400	    variable Idx_v        : integer   := input'low;
401	    variable IsNeg_v      : boolean   := false;
402	    variable ValInt_v     : integer   := 0;
403	    variable ValFrac_v    : real      := 0.0;
404	    variable FracDigits_v : integer   := 0;
405	    variable Exp_v        : integer   := 0;
406	    variable ExpNeg_v     : boolean   := false;
407	    variable ValAbs_v     : real      := 0.0;
408	  begin
409	    -- skip leading white-spaces (space, non-breaking space or horizontal tab)
410	    while (Idx_v <= input'high) and (input(Idx_v) = ' ' or input(Idx_v) = Nbsp_c or input(Idx_v) = HT) loop
411	      Idx_v := Idx_v + 1;
412	    end loop;
413	
414	    -- Check sign
415	    if (Idx_v <= input'high) and ((input(Idx_v) = '-') or (input(Idx_v) = '+')) then
416	      IsNeg_v := (input(Idx_v) = '-');
417	      Idx_v   := Idx_v + 1;
418	    end if;
419	
420	    -- Parse Integer
421	    while (Idx_v <= input'high) and (input(Idx_v) <= '9') and (input(Idx_v) >= '0') loop
422	      ValInt_v := ValInt_v * 10 + (character'pos(input(Idx_v)) - character'pos('0'));
423	      Idx_v    := Idx_v + 1;
424	    end loop;
425	
426	    -- Check decimal point
427	    if (Idx_v <= input'high) then
428	      if input(Idx_v) = '.' then
429	        Idx_v := Idx_v + 1;
430	
431	        -- Parse Fractional
432	        while (Idx_v <= input'high) and (input(Idx_v) <= '9') and (input(Idx_v) >= '0') loop
433	          ValFrac_v    := ValFrac_v * 10.0 + real((character'pos(input(Idx_v)) - character'pos('0')));
434	          FracDigits_v := FracDigits_v + 1;
435	          Idx_v        := Idx_v + 1;
436	        end loop;
437	      end if;
438	    end if;
439	
440	    -- Check exponent
441	    if (Idx_v <= input'high) then
442	      if (input(Idx_v) = 'E') or (input(Idx_v) = 'e') then
443	        Idx_v := Idx_v + 1;
444	        -- Check sign
445	        if (Idx_v <= input'high) and ((input(Idx_v) = '-') or (input(Idx_v) = '+')) then
446	          ExpNeg_v := (input(Idx_v) = '-');
447	          Idx_v    := Idx_v + 1;
448	        end if;
449	
450	        -- Parse Integer
451	        while (Idx_v <= input'high) and (input(Idx_v) <= '9') and (input(Idx_v) >= '0') loop
452	          Exp_v := Exp_v * 10 + (character'pos(input(Idx_v)) - character'pos('0'));
453	          Idx_v := Idx_v + 1;
454	        end loop;
455	        if ExpNeg_v then
456	          Exp_v := -Exp_v;
457	        end if;
458	      end if;
459	    end if;
460	
461	    -- Return
462	    ValAbs_v := (real(ValInt_v) + ValFrac_v / 10.0**real(FracDigits_v)) * 10.0**real(Exp_v);
463	    if IsNeg_v then
464	      return -ValAbs_v;
465	    else
466	      return ValAbs_v;
467	    end if;
468	  end function;
469	
470	  -- convert string to real array
471	  function from_str(input : string) return t_areal is
472	    variable arr      : t_areal(0 to count_array_str_elements(input) - 1) := (others => 0.0);
473	    variable aIdx     : natural                                           := 0;
474	    variable startIdx : natural                                           := 1;
475	    variable endIdx   : natural                                           := 1;
476	    variable idx      : natural                                           := input'low;
477	  begin
478	    while idx <= input'high loop
479	      if input(idx) = ',' then
480	        endIdx    := idx - 1;
481	        arr(aIdx) := from_str(input(startIdx to endIdx));
482	        aIdx      := aIdx + 1;
483	        startIdx  := idx + 1;
484	      end if;
485	      idx := idx + 1;
486	    end loop;
487	    if startIdx <= input'high then
488	      arr(aIdx) := from_str(input(startIdx to input'high));
489	    end if;
490	    return arr;
491	  end function;
492	
493	  --*** get ratio value between two values REAL, used for counter max ***
494	  function ratio(ina : real; inb : real) return integer is
495	    variable res : integer;
496	  begin
497	    if ina > inb then
498	      res := integer(ceil(ina / inb));
499	    elsif ina = inb then
500	      assert false report "both freq. are similar" severity warning;
501	      res := 1;
502	    else
503	      res := integer(ceil(inb / ina));
504	    end if;
505	    return res;
506	  end function;
507	
508	  --*** get ratio value between two values INT, used for counter max ***
509	  function ratio(ina : integer; inb : integer) return integer is
510	    variable res : integer;
511	  begin
512	    if ina > inb then
513	      res := integer(ceil(real(ina) / real(inb)));
514	    elsif ina = inb then
515	      assert false report "both freq. are similar" severity warning;
516	      res := 1;
517	    else
518	      res := integer(ceil(real(inb) / real(ina)));
519	    end if;
520	    return res;
521	  end function;
522	
523	  --*** get the maximum out of an array of integer ***
524	  function max_a(a : in t_ainteger) return integer is
525	    variable max_v : integer := 0;
526	  begin
527	    for idx in a'low to a'high loop
528	      if max(max_v, a(idx)) > max_v then
529	        max_v := a(idx);
530	      end if;
531	    end loop;
532	    return max_v;
533	  end function;
534	
535	  --*** get the maximum out of an array of real ***
536	  function max_a(a : in t_areal) return real is
537	    variable max_v : real := 0.0;
538	  begin
539	    for idx in a'low to a'high loop
540	      if max(max_v, a(idx)) > max_v then
541	        max_v := a(idx);
542	      end if;
543	    end loop;
544	    return max_v;
545	  end function;
546	
547	  --*** get the minimum out of an array of integer ***
548	  function min_a(a : in t_ainteger) return integer is
549	    variable min_v : integer := 0;
550	  begin
551	    for idx in a'low to a'high loop
552	      if min(min_v, a(idx)) < min_v then
553	        min_v := a(idx);
554	      end if;
555	    end loop;
556	    return min_v;
557	  end function;
558	
559	  --*** get the minimum out of an array of real ***
560	  function min_a(a : in t_areal) return real is
561	    variable min_v : real := 0.0;
562	  begin
563	    for idx in a'low to a'high loop
564	      if min(min_v, a(idx)) < min_v then
565	        min_v := a(idx);
566	      end if;
567	    end loop;
568	    return min_v;
569	  end function;
570	
571	  --*** is ratio an integer REAL ***
572	  function is_int_ratio(a : in real; b : in real) return boolean is
573	    variable a_v, b_v : real := 0.0;
574	  begin
575	    -- check > < prior to eval
576	    if a > b then
577	      a_v := real(a);
578	      b_v := real(b);
579	    else
580	      a_v := real(b);
581	      b_v := real(a);
582	    end if;
583	
584	    --eval val
585	    if a_v / b_v = ceil(a_v / b_v) or a_v / b_v = floor(a_v / b_v) then
586	      return true;
587	    else
588	      return false;
589	    end if;
590	  end function;
591	
592	  --*** is ratio an integer REAL ***
593	  function is_int_ratio(a : in integer; b : in integer) return boolean is
594	    variable a_v, b_v : real := 0.0;
595	  begin
596	    -- check > < prior to eval
597	    if a > b then
598	      a_v := real(a);
599	      b_v := real(b);
600	    else
601	      a_v := real(b);
602	      b_v := real(a);
603	    end if;
604	
605	    --eval val
606	    if a_v / b_v = ceil(a_v / b_v) or a_v / b_v = floor(a_v / b_v) then
607	      return true;
608	    else
609	      return false;
610	    end if;
611	
612	  end function;
613	  
614	  --*** find the nearest power 2, used for AXI register count not synth***
615	  function nearest_pow2(a: integer) return integer is
616	      variable power_of_two : unsigned(31 downto 0);    -- Adjust size if needed
617	      variable num_bits     : integer;
618	    begin
619	        num_bits     := 32;
620	        power_of_two := (others => '0');
621	        
622	        for i in 0 to num_bits-1 loop
623	            if (2**i >= a) then
624	                power_of_two    := (others => '0');
625	                power_of_two(i) := '1';
626	                exit;
627	            end if;
628	        end loop;        
629	        return to_integer(power_of_two);   
630	    end function;
631	    
632	end psi_common_math_pkg;
