11	use work.psi_common_math_pkg.all;
12	
13	------------------------------------------------------------------------------
14	-- Package Header
15	------------------------------------------------------------------------------
16	package psi_common_logic_pkg is
17	
18	  function zeros_vector(size : in natural) return std_logic_vector;
19	
20	  function ones_vector(size : in natural) return std_logic_vector;
21	
22	  function partially_ones_vector(size    : in natural;
23	                                 ones_nb : in natural)
24	  return std_logic_vector;
25	
26	  function shift_left(arg  : in std_logic_vector;
27	                      bits : in integer;
28	                      fill : in std_logic := '0')
29	  return std_logic_vector;
30	
31	  function shift_right(arg  : in std_logic_vector;
32	                       bits : in integer;
33	                       fill : in std_logic := '0')
34	  return std_logic_vector;
35	
36	  function binary_to_gray(binary : in std_logic_vector)
37	  return std_logic_vector;
38	
39	  function gray_to_binary(gray : in std_logic_vector)
40	  return std_logic_vector;
41	
42	  -- Parallel Prefix Computation of the OR function
43	  -- Input 	--> Output
44	  -- 0100		--> 0111
45	  -- 0101		--> 0111
46	  -- 0011		--> 0011
47	  -- 0010		--> 0011
48	  function ppc_or(inp : in std_logic_vector)
49	  return std_logic_vector;
50	
51	  function int_to_std_logic(int : in integer)
52	  return std_logic;
