------------------------------------------------------------------------------
--  Copyright (c) 2018 by Paul Scherrer Institute, Switzerland
--  Copyright (c) 2023 by Oliver BrÃÂÃÂ¼ndler
--  All rights reserved.
--  Authors: Oliver Bruendler
------------------------------------------------------------------------------

------------------------------------------------------------------------------
-- Description
------------------------------------------------------------------------------
-- This entity implements a pipelinestage with handshaking (AXI-S RDY/VLD). The
-- pipeline stage ensures all signals are registered in both directions (including
-- RDY). This is important to break long logic chains that can occur in the RDY
-- paths because Rdy is often forwarded asynchronously.

library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;
use ieee.math_real.all;

-- @formatter:off
entity psi_common_pl_stage is
  generic(width_g   : integer   := 8;                             -- data vector length
          use_rdy_g : boolean   := true;                          -- use ready push back signals
          rst_pol_g : std_logic := '1');                          -- '1' active high, '0' active low
  port(   clk_i     : in  std_logic;                              -- system clock
          rst_i     : in  std_logic;                              -- system reset
          vld_i     : in  std_logic;                              -- valid input
          rdy_o     : out std_logic;                              -- rdy output - push back
          dat_i     : in  std_logic_vector(width_g - 1 downto 0); -- datra input
          vld_o     : out std_logic;                              -- valid output
          rdy_i     : in  std_logic := '1';                       -- rdy input - push back
          dat_o     : out std_logic_vector(width_g - 1 downto 0));-- data output
end entity;
-- @formatter:on

architecture rtl of psi_common_pl_stage is
  -- two process method
  type tp_r is record
    DataMain    : std_logic_vector(width_g - 1 downto 0);
    DataMainVld : std_logic;
    DataShad    : std_logic_vector(width_g - 1 downto 0);
    DataShadVld : std_logic;
    rdy_o       : std_logic;
  end record;
  signal r, r_next : tp_r;

begin

  -- *** Pipeline Stage with RDY ***
  g_rdy : if use_rdy_g generate

    p_comb : process(vld_i, dat_i, rdy_i, r)
      variable v         : tp_r;
      variable IsStuck_v : boolean;
    begin
      -- *** Hold variables stable ***
      v := r;

      -- *** Simplification Variables ***
      IsStuck_v := (r.DataMainVld = '1' and rdy_i = '0' and (vld_i = '1' or r.DataShadVld = '1'));

      -- *** Handle output transactions ***
      if r.DataMainVld = '1' and rdy_i = '1' then
        v.DataMainVld := r.DataShadVld;
        v.DataMain    := r.DataShad;
        v.DataShadVld := '0';
      end if;

      -- *** Latch incoming data ***
      if r.rdy_o = '1' and vld_i = '1' then
        -- If we are stuck, save data in shadow register because ready is deasserted only after one clock cycle
        if IsStuck_v then
          v.DataShadVld := '1';
          v.DataShad    := dat_i;
        -- In normal case, forward data directly to the output registers
        else
          v.DataMainVld := '1';
          v.DataMain    := dat_i;
        end if;
      end if;

      -- *** Remove Rdy if stuck ***
      if IsStuck_v then
        v.rdy_o := '0';
      else
        v.rdy_o := '1';
      end if;

      -- *** Assign to signal ***
      r_next <= v;
    end process;

    rdy_o <= r.rdy_o;
    vld_o <= r.DataMainVld;
    dat_o <= r.DataMain;

    p_seq : process(clk_i)
    begin
      if rising_edge(clk_i) then
        r <= r_next;
        if rst_i = rst_pol_g then
          r.DataMainVld <= '0';
          r.DataShadVld <= '0';
          r.rdy_o       <= '1';
        end if;
      end if;
    end process;
  end generate;


  -- *** Pipeline Stage without RDY ***
  g_nrdy : if not use_rdy_g generate
    rdy_o <= '0';
    p_stg : process(clk_i)
    begin
      if rising_edge(clk_i) then
        dat_o <= dat_i;
        vld_o <= vld_i;
        if rst_i = rst_pol_g then
          vld_o <= '0';
        end if;
      end if;
    end process;
  end generate;

end architecture;

------------------------------------------------------------------------------
--  Copyright (c) 2018 by Paul Scherrer Institute, Switzerland
--  All rights reserved.
--  Authors: Oliver Bruendler
------------------------------------------------------------------------------

------------------------------------------------------------------------------
-- Description
------------------------------------------------------------------------------
-- This is a very basic clock crossing that allows passing single samples of data
-- from one clock domain to another. It only works if sample rates are significantly
-- lower than the clock speed of both domains.

library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;

-- @formatter:off
entity psi_common_simple_cc is
  generic(width_g      : positive := 16;                                  --  Width of the data signal to implement the clock crossing for
          a_rst_pol_g  : std_logic:='1';                                  --  reset polarity A port
          b_rst_pol_g  : std_logic:='1');                                 --  reset polarity B port
  port(   a_clk_i      : in  std_logic;                                   --  Clock A
          a_rst_i      : in  std_logic;                                   --  Clock domain A reset input (active high)
          a_rst_o      : out std_logic;                                   --  Clock domain A reset output (active high), active if *RstInA* or *RstInB* is asserted, de-asserted synchronously to *ClkA*
          a_dat_i      : in  std_logic_vector(width_g - 1 downto 0);      --  Data signal input
          a_vld_i      : in  std_logic;                                   --  AXI-S handshaking signal
          b_clk_i      : in  std_logic;                                   --  Clock B
          b_rst_i      : in  std_logic;                                   --  Clock domain A reset input (active high)
          b_rst_o      : out std_logic;                                   --  Clock domain B reset output (active high), active if *RstInA* or *RstInB* is asserted, de-asserted synchronously to *ClkA*
          b_dat_o      : out std_logic_vector(width_g - 1 downto 0);      --  Data signal output
          b_vld_o      : out std_logic);                                  --  AXI-S handshaking signal
end entity;
-- @formatter:on

architecture rtl of psi_common_simple_cc is
  -- Domain A signals
  signal RstAI      : std_logic;
  signal DataLatchA : std_logic_vector(width_g - 1 downto 0);
  -- Domain B signals
  signal RstBI      : std_logic;
  signal VldBI      : std_logic;

begin

  i_pulse_cc : entity work.psi_common_pulse_cc
    generic map(
      num_pulses_g => 1,
      a_rst_pol_g => a_rst_pol_g,
      b_rst_pol_g => b_rst_pol_g
    )
    port map(
      a_clk_i    => a_clk_i,
      a_rst_i    => a_rst_i,
      a_rst_o    => RstAI,
      a_dat_i(0) => a_vld_i,
      b_clk_i    => b_clk_i,
      b_rst_i    => b_rst_i,
      b_rst_o    => RstBI,
      b_dat_o(0) => VldBI
    );
  a_rst_o <= RstAI;
  b_rst_o <= RstBI;

  -- Data transmit side (A)
  DataA_p : process(a_clk_i)
  begin
    if rising_edge(a_clk_i) then
      if RstAI = a_rst_pol_g then
        DataLatchA <= (others => '0');
      else
        if a_vld_i = '1' then
          DataLatchA <= a_dat_i;
        end if;
      end if;
    end if;
  end process;

  -- Data receive side (B)
  DataB_p : process(b_clk_i)
  begin
    if rising_edge(b_clk_i) then
      if RstBI = b_rst_pol_g then
        b_dat_o <= (others => '0');
        b_vld_o <= '0';
      else
        b_vld_o <= VldBI;
        if VldBI = '1' then
          b_dat_o <= DataLatchA;
        end if;
      end if;
    end if;
  end process;

end architecture;

