7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This is a pure VHDL and vendor indpendent simple dual port RAM.
11	
12	library ieee;
13	use ieee.std_logic_1164.all;
14	use ieee.numeric_std.all;
15	
16	use work.psi_common_math_pkg.all;
17	
18	entity psi_common_sdp_ram is
19	  generic(depth_g        : positive := 1024;                                                         -- memory depthg, samples
20	          width_g        : positive := 16;                                                           -- data length
21	          is_async_g     : boolean  := false;                                                        -- True = Separate Rd clock is used (clk is WrClk in this case)
22	          ram_style_g    : string   := "auto";                                                       -- "auto", "distributed" or "block"
23	          ram_behavior_g : string   := "RBW");                                                       -- "RBW" = read-before-write, "WBR" = write-before-read
24	  port(   wr_clk_i       : in  std_logic                                        := '0';              -- write clock
25	          wr_addr_i      : in  std_logic_vector(log2ceil(depth_g) - 1 downto 0) := (others => '0');  -- write address
26	          wr_i           : in  std_logic                                        := '0';              -- write enable
27	          wr_dat_i       : in  std_logic_vector(width_g - 1 downto 0)           := (others => '0');  -- write data input
28	          rd_clk_i       : in  std_logic                                        := '0';              -- read clock
29	          rd_addr_i      : in  std_logic_vector(log2ceil(depth_g) - 1 downto 0) := (others => '0');  -- read address
30	          rd_i           : in  std_logic                                        := '1';              -- read enable
31	          rd_dat_o       : out std_logic_vector(width_g - 1 downto 0));                              -- read data output
32	end entity;
33	
34	architecture rtl of psi_common_sdp_ram is
35	
36	  -- memory array
37	  type mem_t is array (depth_g - 1 downto 0) of std_logic_vector(width_g - 1 downto 0);
38	  shared variable mem : mem_t := (others => (others => '0'));
39	  attribute ram_style : string;
40	  attribute ram_style of mem : variable is ram_style_g;
41	
42	begin
43	  -- Synchronous Implementation
44	  g_sync : if not is_async_g generate
45	    ram_p : process(wr_clk_i)
46	    begin
47	      if rising_edge(wr_clk_i) then
48	        if ram_behavior_g = "RBW" then
49	          if rd_i = '1' then
50	            rd_dat_o <= mem(to_integer(unsigned(rd_addr_i)));
51	          end if;
52	        end if;
53	        if wr_i = '1' then
54	          mem(to_integer(unsigned(wr_addr_i))) := wr_dat_i;
55	        end if;
56	        if ram_behavior_g = "WBR" then
57	          if rd_i = '1' then
58	            rd_dat_o <= mem(to_integer(unsigned(rd_addr_i)));
59	          end if;
60	        end if;
61	      end if;
62	    end process;
63	  end generate;
64	
65	  -- Asynchronous implementation
66	  g_async : if is_async_g generate
67	
68	    write_p : process(wr_clk_i)
69	    begin
70	      if rising_edge(wr_clk_i) then
71	        if wr_i = '1' then
