28	          a_rst_o      : out std_logic;                                    -- Clock domain A reset output, active if *a_rst_i* or *b_rst_i* is asserted, de-asserted synchronously to *a_clk_i*
29	          a_dat_i      : in  std_logic_vector(num_pulses_g - 1 downto 0);  -- dat input port a
