31	          b_rst_i      : in  std_logic;                                    -- rst input port b
32	          b_rst_o      : out std_logic;                                    -- Clock domain B reset output, active if *a_rst_i* or *b_rst_i* is asserted, de-asserted synchronously to *b_clk_i*
33	          b_dat_o      : out std_logic_vector(num_pulses_g - 1 downto 0)); -- dat output port b
