38	
39	  type Pulse_t is array (natural range <>) of std_logic_vector(num_pulses_g - 1 downto 0);
40	
41	  -- Domain A signals
42	  signal RstSyncB2A  : std_logic_vector(3 downto 0);
43	  signal RstAI       : std_logic  :=  a_rst_pol_g;
